import { ethers } from 'ethers';

// Constants
const TOKEN_CONTRACT_ADDRESS = '0xYourTokenContractAddress';
const DEX_CONTRACT_ADDRESS = '0xYourDEXContractAddress';
const APPROVAL_AMOUNT = ethers.constants.MaxUint256;

async function swapTokens(provider, privateKey) {
  // Connect to the provider and wallet
  const wallet = new ethers.Wallet(privateKey, provider);

  // Get token contract instance
  const tokenContract = new ethers.Contract(TOKEN_CONTRACT_ADDRESS, [
    'function approve(address spender, uint256 amount) public returns (bool)',
    'function transferFrom(address from, address to, uint256 value) public returns (bool)'
  ], wallet);

  // Get DEX contract instance
  const dexContract = new ethers.Contract(DEX_CONTRACT_ADDRESS, [
    'function swapTokens(address tokenIn, address tokenOut, uint256 amountIn) public'
  ], wallet);

  try {
    // Approve the DEX to spend tokens
    const approveTx = await tokenContract.approve(DEX_CONTRACT_ADDRESS, APPROVAL_AMOUNT);
    await approveTx.wait();

    console.log('Approval successful');

    // Perform the swap
    const swapTx = await dexContract.swapTokens(TOKEN_CONTRACT_ADDRESS, '0xOtherTokenAddress', ethers.utils.parseEther('1.0'));
    await swapTx.wait();

    console.log('Swap successful');
  } catch (error) {
    console.error('Error during token swap:', error);
  }
}

